import pytest
import time

def test_bulk_export_job_transitions_from_accepted_to_completed(
    authorised_bulk_client,  # <fixture>
    fhir_base_url,           # <fixture>
):
    headers = {"Accept": "application/fhir+json", "Prefer": "respond-async"}
    kick = authorised_bulk_client.get(f"{fhir_base_url}/$export", headers=headers)
    assert kick.status_code == 202, "State: ACCEPTED expected"
    status_url = kick.headers["Content-Location"]

    states_seen = ["ACCEPTED"]
    deadline = time.time() + 45
    while time.time() < deadline:
        poll = authorised_bulk_client.get(status_url)
        if poll.status_code == 202:
            if "IN-PROGRESS" not in states_seen:
                states_seen.append("IN-PROGRESS")
        elif poll.status_code == 200:
            states_seen.append("COMPLETE")
            break
        else:
            pytest.fail(f"Unexpected status {poll.status_code} during polling")
        time.sleep(2)
    else:
        pytest.fail("Export did not reach COMPLETE state within timeout")

    assert "COMPLETE" in states_seen
    # Verify terminal: second read of manifest still 200, not regressed
    recheck = authorised_bulk_client.get(status_url)
    assert recheck.status_code == 200, "COMPLETE state must be stable on re-poll"
    assert states_seen.index("COMPLETE") == len(states_seen) - 1, (
        "State regressed after COMPLETE"
    )
